<script setup lang="ts">
import { computed } from 'vue'
import type { DadsCarouselSingleProps } from './DadsCarouselSingle.types'

const props = defineProps<DadsCarouselSingleProps>()

// 公式マークアップではリンク有無でラッパ要素を切り替える。
// href があれば <a>、無ければ <span>（CSS は :any-link で両者を区別する）。
const isLink = computed(() => Boolean(props.href))
const wrapperTag = computed(() => (isLink.value ? 'a' : 'span'))
</script>

<template>
  <div class="dads-carousel-single">
    <component
      :is="wrapperTag"
      class="dads-carousel-single__link"
      :href="isLink ? href : undefined"
      :target="isLink ? target : undefined"
      :rel="isLink ? rel : undefined"
    >
      <img
        class="dads-carousel-single__image"
        :src="src"
        :srcset="srcset"
        :alt="alt"
        :width="width"
        :height="height"
      />
    </component>
  </div>
</template>

